llm_verdict.message:
{
  "explanation": "Ensure PASS_MAX_DAYS is set to 90 days in /etc/login.defs by removing any existing line and appending the correct setting.",
  "commands": [
    {
      "command": "sed -i '/^PASS_MAX_DAYS/d' /etc/login.defs"
    },
    {
      "command": "echo 'PASS_MAX_DAYS=90' >> /etc/login.defs"
    },
    {
      "command": "cat /etc/login.defs"
    }
  ]
}
